const { execSync } = require('child_process');
const action = params.action || 'configtest';
if (action === 'configtest') {
  const result = execSync('nginx -t 2>&1 || true', { encoding: 'utf-8', timeout: 10000 });
  return { output: result };
} else if (action === 'version') {
  const result = execSync('nginx -v 2>&1', { encoding: 'utf-8', timeout: 10000 });
  return { output: result };
} else if (action === 'sites') {
  const fs = require('fs');
  const sitesDir = params.sitesDir || '/etc/nginx/sites-enabled';
  if (!fs.existsSync(sitesDir)) {
    return { output: 'Sites directory not found', sites: [] };
  }
  const sites = fs.readdirSync(sitesDir).filter(f => f.endsWith('.conf') || !f.includes('.'));
  return { sites };
} else {
  throw new Error('Unknown action: ' + action);
}
